import logging
import envoy_auth_grpc
from concurrent import futures

class CustomExternalAuthorizer(envoy_auth_grpc.AbstractExternalAuthorizer):

    def check(self, request, context):
        # Access custom headers from the request
        custom_header_value = request.headers.get("custom-header")

        # Perform authorization logic based on custom header value
        if custom_header_value == "authorized":
            return envoy_auth_grpc.CheckResponse(status=envoy_auth_grpc.CheckStatus.OK)
        else:
            return envoy_auth_grpc.CheckResponse(status=envoy_auth_grpc.CheckStatus.DENIED)

def serve():
    server = envoy_auth_grpc.Server([CustomExternalAuthorizer()])
    server.add_insecure_port("[::]:8080")
    server.start()
    server.wait_for_termination()

if __name__ == "__main__":
    logging.basicConfig(level=logging.INFO)
    serve()